#!/usr/bin/env bash
# street-documentary.sh — 纪实/街头扫街 (Street / Documentary) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="纪实/街头扫街 (Street / Documentary)"

usage() {
  cat <<EOF
street-documentary.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./street-documentary.sh             # interactive
  ./street-documentary.sh --dry-run
  ./street-documentary.sh --json
  ./street-documentary.sh --explain
  ./street-documentary.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "纪实/街头扫街 (Street / Documentary)" 工作流。

一句话: 在不可控的公共空间里，靠预对焦、预判、伦理化接近，等到并抓住「决定性瞬间」——抓取派的核心闭环，也是 AI 伦理红线最硬的领域。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**预对焦/区域对焦 zone focusing**: 手动把焦点设到固定距离（如 2–3 米）+ 收小光圈（f/8–f/16）让一段「焦区」恒定清晰，进区即合焦。跳过 → 靠 AF 半按等合焦，错过瞬间或追焦拉风箱。(evidence: [T03-S016, T03-S017])"
  "**设好曝光基底**: 街头光变化大，常用光圈优先或全手动 + Auto ISO，先把曝光定个安全档不临场调。跳过 → 关键瞬间还在拨参数，错过。(evidence: [T03-S016])"
  "**预判 + 观察**: 找有潜力的光/背景/舞台，预判谁会走进画面、下一秒会发生什么，提前构好图等（「为惊喜做准备」）。跳过 → 看到才举机，永远慢半拍。(evidence: [T03-S024])"
  "**接近 + 伦理**: 「不够好是因为不够近」靠近主体；同时处理拍摄伦理（眼神/尊重/必要时交流/当地法规）。跳过接近 → 远摄裁切松散无张力；跳过伦理 → 冲突/侵犯/声誉风险。(evidence: [T04-S004])"
  "**等待决定性瞬间 + 抓拍**: 在构好的框里等元素（人/光/姿态）对齐到峰值再按。跳过 → 乱拍碰运气，几何/时机都不对。(evidence: [T04-S004])"
)
declare -a FAILURE_MODES=(
  "**靠 AF 等合焦错过瞬间**: 追焦拉风箱 → 改区域对焦/超焦距预设固定焦区，进区即拍。**CLI 自检**: 「你预对焦到固定距离了吗，还是每张都让 AF 重新找？」"
  "**远摄裁切代替接近**: 画面松散无张力 → 物理靠近（安全/伦理前提下），不够好是因为不够近。"
  "**越线用生成式 AI**: 纪实/新闻用 Generative Fill 移除/添加元素 = 伦理 + 资格双杀 → 纪实只允许去噪/基础调整，绝不引入新信息。**CLI 自检**: 「这是纪实/新闻吗？那你只能去噪/调基础影调，移除/添加任何元素都越线。」"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "street-documentary-walkthrough"
fi
